import * as React from "react";
import Layout from "../components/Layout";
import { useStaticQuery, graphql } from "gatsby";
import { Box, BaseStyles, Flex, Text, Heading, Link } from "theme-ui";
import SEO from "../components/seo";
import DetailTitle from "../components/DetailTitle";
import DetailNav from "../components/DetailNav";
import FooterNav from "../components/FooterNav";
import { useScrollSpy } from "../hooks/use-scrollspy";

// markup
const IndexPage = ({ location, data, pageContext }) => {
  const item = data.markdownRemark;
  const headings = item.headings;
  const awesomeMeta = data.awesomeList;
  const readmeParsedAt = data.awesomeListMeta.readmeParsedAt;
  let previousInfo = null;
  if (data.previous) {
    previousInfo = {
      name: data.previous.fields.repo,
      url: `/${data.previous.fields.repo}/readme/`,
    };
  }
  let nextInfo = null;

  if (data.next) {
    nextInfo = {
      name: data.next.fields.repo,
      url: `/${data.next.fields.repo}/readme/`,
    };
  }
  let title = `View ${pageContext.repo} Readme With Stars`;
  let description = data.awesomeList.description;
  const activeId = useScrollSpy(
    headings.map(({ id }) => `[id="${id}"]`),
    {
      rootMargin: "0% 0% -24% 0%",
    }
  );
  return (
    <Layout location={location}>
      <SEO title={title} description={description} article />

      <Box p="default">
        <DetailTitle meta={awesomeMeta}></DetailTitle>
        <Flex>
          <Box>
            <DetailNav location={location} meta={awesomeMeta}></DetailNav>
            <Box pt="default">
              <Box
                variant="docs.date"
                sx={{
                  maxWidth: "4xl",
                }}
              >
                <BaseStyles>
                  <div
                    dangerouslySetInnerHTML={{
                      __html: item.html,
                    }}
                  ></div>
                </BaseStyles>
              </Box>
            </Box>
          </Box>

          <Box
            px="default"
            pl="md"
            pt="60px"
            sx={{
              display: ["none", "none", "block"],
              bg: "background",
              width: "300px",
              position: "sticky",
              top: "0px",
              height: "calc(100vh - 60px)",
              overflowY: "auto",
              overscrollBehavior: "contain",
            }}
          >
            <Heading as="h4">ON THIS PAGE</Heading>
            <Box p="0" as="ol" ml="0" mt="3" sx={{ listStyle: "none" }}>
              {headings.map(({ id, value, depth }) => {
                if (depth > 3) {
                  return null;
                }
                return (
                  <Box
                    as="li"
                    key={id}
                    p="0"
                    sx={{ listStyle: "none" }}
                    title={value}
                    ml={depth === 1 || depth === 2 ? "0" : "3"}
                  >
                    <Link
                      py="1"
                      variant="toc"
                      sx={{
                        display: "block",
                        fontWeight: id === activeId ? "bold" : "medium",
                        img: {
                          display: "none",
                        },
                        "[data-role=trackawesomelist-badge]": {
                          display: "none",
                        },
                      }}
                      href={`#${id}`}
                      aria-current={id === activeId ? "location" : undefined}
                      dangerouslySetInnerHTML={{
                        __html: value,
                      }}
                    ></Link>
                  </Box>
                );
              })}
            </Box>
          </Box>
        </Flex>

        <Flex sx={{ justifyContent: "flex-end", maxWidth: "5xl" }}>
          <Box>
            Last Checked At: <Text color="textMuted">{readmeParsedAt}</Text>
          </Box>
        </Flex>
        <FooterNav previous={previousInfo} next={nextInfo}></FooterNav>
      </Box>
    </Layout>
  );
};

export default IndexPage;
export const pageQuery = graphql`
  query awesomeReadme(
    $id: String!
    $repo: String!
    $previousId: String
    $nextId: String
  ) {
    site {
      siteMetadata {
        title
      }
    }
    markdownRemark(id: { eq: $id }) {
      id
      html
      tableOfContents(maxDepth: 3)
      headings {
        id
        value
        depth
      }
    }
    awesomeList(repo: { eq: $repo }) {
      repo
      description
      descriptionHTML
    }
    awesomeListMeta(repo: { eq: $repo }) {
      readmeParsedAt
    }
    previous: markdownRemark(id: { eq: $previousId }) {
      id
      fields {
        repo
        slug
      }
    }
    next: markdownRemark(id: { eq: $nextId }) {
      id
      fields {
        repo
        slug
      }
    }
  }
`;
